db.create_all()

def generate_video_stream(video_path, start_time=0):
    def generate():
        with open(video_path, 'rb') as f:
            f.seek(start_time * 1024 * 1024)  # Seek to start time in bytes
            while True:
                chunk = f.read(1024 * 1024)  # Read in 1MB chunks
                if not chunk:
                    break
                yield chunk
    return generate()

@app.route('/upload', methods=['POST'])
def upload_video():
    if 'file' not in request.files:
        return 'No file part', 400
    file = request.files['file']
    if file.filename == '':
