    filename = secure_filename(file.filename)
    file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    file.save(file_path)

    # Generate resolutions
    resolutions = ['360p', '480p', '720p', '1080p']
    for res in resolutions:
        output_path = os.path.join(app.config['UPLOAD_FOLDER'], f"{filename}_{res}.mp4")
        clip = VideoFileClip(file_path)
        clip.resize(newsize=(int(clip.w * int(res[:-1]) / 1080), int(clip.h * int(res[:-1]) / 1080))).write_videofile(output_path)
        new_video = Video(filename=f"{filename}_{res}.mp4", resolution=res)
        db.session.add(new_video)
    db.session.commit()
    return 'File uploaded and processed', 201

